# k8s_network_policy.py
# Generates Kubernetes NetworkPolicy YAML for AI agent sandboxes.
# Apply with: python3 k8s_network_policy.py | kubectl apply -f -
import yaml  # pip install pyyaml
from typing import Any


def build_agent_network_policy(
    name: str,
    namespace: str,
    agent_label: str,
    allowed_egress_pods: list[dict[str, Any]],
    allowed_egress_ips: list[dict[str, Any]],
) -> dict[str, Any]:
    """
    Build a default-deny Kubernetes NetworkPolicy:
    - Denies ALL ingress (agents cannot accept connections)
    - Denies all egress except:
      (a) DNS on UDP/53 to kube-system
      (b) Explicitly allowed internal pods
      (c) Explicitly allowed external IP blocks
    """
    egress_rules: list[dict[str, Any]] = [
        # Always allow DNS to the cluster resolver
        {
            "ports": [{"protocol": "UDP", "port": 53}],
            "to": [{
                "namespaceSelector": {
                    "matchLabels": {"kubernetes.io/metadata.name": "kube-system"}
                }
            }]
        }
    ]

    # Internal service pods
    for pod_selector in allowed_egress_pods:
        egress_rules.append({
            "to": [{"podSelector": pod_selector}],
            "ports": [{"protocol": "TCP", "port": 443}]
        })

    # External IP ranges (e.g. LLM provider, monitoring)
    for ip_rule in allowed_egress_ips:
        egress_rules.append({
            "to": [{"ipBlock": {"cidr": ip_rule["cidr"]}}],
            "ports": [{
                "protocol": ip_rule.get("protocol", "TCP"),
                "port": ip_rule["port"]
            }]
        })

    return {
        "apiVersion": "networking.k8s.io/v1",
        "kind": "NetworkPolicy",
        "metadata": {"name": name, "namespace": namespace},
        "spec": {
            "podSelector": {"matchLabels": {"app": agent_label}},
            "policyTypes": ["Ingress", "Egress"],
            "ingress": [],          # empty list = deny all ingress
            "egress": egress_rules,
        }
    }


def main() -> None:
    policy = build_agent_network_policy(
        name="ai-agent-network-isolation",
        namespace="agents",
        agent_label="ai-agent",
        allowed_egress_pods=[
            {"matchLabels": {"app": "internal-logging"}},
            {"matchLabels": {"app": "vector-store"}},
        ],
        allowed_egress_ips=[
            # Replace with actual resolved CIDR for your LLM provider
            {"cidr": "52.2.100.0/24", "port": 443, "protocol": "TCP"},
        ]
    )
    print(yaml.dump(policy, default_flow_style=False, sort_keys=False))


if __name__ == "__main__":
    main()

# WRONG: default-allow with blocklist -- trivially evaded
BLOCKLIST = {"evil.com", "malware.net", "c2.attacker.io"}

def is_destination_allowed(dest: str) -> bool:
    # An attacker uses ANY domain not in this list
    return dest not in BLOCKLIST


# RIGHT: default-deny with allowlist -- only pre-approved destinations succeed
ALLOWLIST = {"api.anthropic.com", "storage.internal.corp", "logging.internal:5044"}

def is_destination_allowed(dest: str) -> bool:
    return dest in ALLOWLIST


# Even better: enforce this at the network layer (iptables/NetworkPolicy),
# not just in application code -- application-level checks can be bypassed
# by prompt injection that causes the agent to call httpx or socket directly.
